//! Compilation of aux_gen-generated constants into Ixon blocks.
//!
//! This module handles two related tasks:
//!
//! 1. **`compile_aux_block`**: Takes a set of `MutConst` values (recursors,
//!    definitions, inductives) generated by aux_gen and compiles them into an
//!    Ixon mutual block with projections, reusing the same sort/compile/register
//!    pipeline as `compile_mutual` in the parent module.
//!
//! 2. **`generate_and_compile_aux_recursors`**: Orchestrates the full aux_gen
//!    pipeline: generates canonical patches (recursors, `.below`, `.brecOn`),
//!    then compiles each phase's output via `compile_aux_block`.

use std::sync::Arc;

use rustc_hash::FxHashMap;

use lean_ffi::nat::Nat;

use crate::ix::address::Address;
use crate::ix::compile::aux_gen::below::BelowIndc;
use crate::ix::compile::aux_gen::brecon::BRecOnDef;
use crate::ix::compile::aux_gen::recursor;
use crate::ix::compile::aux_gen::{self, PatchedConstant};
use crate::ix::compile::{
  BlockCache, CompileState, collect_mut_const_exprs, compile_definition,
  compile_inductive, compile_mutual_block, compile_name, compile_recursor,
  preseed_expr_tables, sort_consts,
};
use crate::ix::env::{
  ConstantInfo as LeanConstantInfo, ConstantVal, ConstructorVal,
  DefinitionSafety, Env as LeanEnv, Name, ReducibilityHints,
};
use crate::ix::ixon::{
  CompileError,
  constant::{
    Constant, ConstantInfo, ConstructorProj, DefKind, DefinitionProj,
    InductiveProj, MutConst as IxonMutConst, RecursorProj,
  },
  env::Named,
  metadata::{ConstantMeta, ConstantMetaInfo},
  univ::Univ,
};
use crate::ix::mutual::{Def, Ind, MutConst};

// ===========================================================================
// compile_aux_block
// ===========================================================================

/// Compile a set of aux_gen-produced constants into an Ixon mutual block.
///
/// This is the aux_gen analogue of `compile_mutual` in the parent module:
/// it sorts constants into equivalence classes, compiles each representative,
/// creates the mutual block, and registers projections + names.
///
/// Compiled constants are registered in `stt.aux_name_to_addr` (not
/// `stt.name_to_addr`) so they don't interfere with the scheduler's
/// dependency tracking. The scheduler's promotion path in `env.rs` moves
/// them to `name_to_addr` when the block is processed.
pub(crate) fn compile_aux_block(
  aux_consts: &[MutConst],
  lean_env: &Arc<LeanEnv>,
  stt: &CompileState,
) -> Result<(), CompileError> {
  compile_aux_block_with_rename(aux_consts, lean_env, stt, None, None)
}

/// Like `compile_aux_block`, but applies an optional name-rename map when
/// registering named entries in the env.
///
/// The rename maps *canonical* constant names (the `cnst.name()` of
/// `aux_consts` entries, produced by `aux_gen` at hash-sorted positions)
/// to *source* names (what Lean's env exports for the same content).
///
/// For nested-auxiliary recursors/definitions (`.rec_N`, `.below_N`,
/// `.brecOn_N[.go|.eq]`) the canonical naming uses hash-sorted indices
/// while Lean uses source-walk indices. Without the rename, user code
/// referencing Lean's `X.rec_1` would resolve to the canonical aux at
/// index 0 (wrong semantic position under non-identity `perm`).
///
/// The rename is applied at:
///   * `stt.env.register_name`  — so lookups hit the source name
///   * `stt.aux_name_to_addr`   — so scheduler deps resolve source names
///   * `stt.aux_gen_extra_names`— so membership checks use source names
///   * `muts_all` name hashes   — so kernel ingress's `ingress_muts_block`
///     looks up the source Named entry at each canonical block position
///
/// `class_order_key`, when provided, is used to reorder the classes
/// produced by `sort_consts` before they're laid out in the block. Used by
/// the recursor block path to align stored block positions with the
/// inductive block's flat layout: the kernel's `populate_recursor_rules_from_block`
/// expects `rec_block[i]` to be the recursor for `flat[i]`, where `flat` is
/// `[originals (in inductive-block class order), aux (in canonical_aux_order)]`.
/// Without this reorder, `sort_consts` on recursors picks an independent
/// canonical permutation that diverges from the inductive block's layout.
/// See `docs/ix_canonicity.md` §6.2 and the rationale in
/// `kernel::inductive::populate_recursor_rules_from_block`.
///
/// The class ordering produced by `sort_consts` is preserved as a
/// stable tiebreak: classes that map to `u64::MAX` (no key entry) keep
/// their `sort_consts` relative position at the tail.
pub(crate) fn compile_aux_block_with_rename(
  aux_consts: &[MutConst],
  lean_env: &Arc<LeanEnv>,
  stt: &CompileState,
  name_rename: Option<&FxHashMap<Name, Name>>,
  class_order_key: Option<&dyn Fn(&MutConst) -> u64>,
) -> Result<(), CompileError> {
  if aux_consts.is_empty() {
    return Ok(());
  }
  let mut cache = BlockCache::default();

  // Helper: given a canonical name, return the source name if a rename
  // is in effect, otherwise return the canonical name unchanged.
  let resolve_name = |canon: &Name| -> Name {
    name_rename
      .and_then(|m| m.get(canon).cloned())
      .unwrap_or_else(|| canon.clone())
  };

  // Sort into equivalence classes (same algorithm as compile_mutual).
  let refs: Vec<&MutConst> = aux_consts.iter().collect();
  let mut sorted_classes = sort_consts(&refs, &mut cache, stt)?;

  // Optional class reorder: callers (recursor block path) supply a key
  // that maps each class member to its canonical block position. Sort
  // classes by the minimum key over the class — well-formed callers give
  // every member of a class the same key, so this is just `key(class[0])`
  // in practice. `sort_by_key` is stable, so classes with the same key
  // keep their `sort_consts` relative order.
  if let Some(key_fn) = class_order_key {
    sorted_classes.sort_by_key(|class| {
      class.iter().map(|c| key_fn(c)).min().unwrap_or(u64::MAX)
    });
  }

  let mut_ctx = MutConst::ctx(&sorted_classes);

  let mut exprs = Vec::new();
  for cnst in aux_consts {
    collect_mut_const_exprs(cnst, &mut exprs);
  }
  preseed_expr_tables(&exprs, &mut_ctx, &mut cache, stt, "compile_aux_block")?;

  // Compile each representative per class.
  let mut ixon_mutuals = Vec::new();
  let mut all_metas: FxHashMap<Name, ConstantMeta> = FxHashMap::default();

  for class in &sorted_classes {
    let mut rep_pushed = false;
    for cnst in class {
      match cnst {
        MutConst::Recr(rec) => {
          let (data, meta) = compile_recursor(rec, &mut_ctx, &mut cache, stt)?;
          if !rep_pushed {
            ixon_mutuals.push(IxonMutConst::Recr(data));
            rep_pushed = true;
          }
          all_metas.insert(rec.cnst.name.clone(), meta);
        },
        MutConst::Defn(def) => {
          let (data, meta) =
            compile_definition(def, &mut_ctx, &mut cache, stt)?;
          if !rep_pushed {
            ixon_mutuals.push(IxonMutConst::Defn(data));
            rep_pushed = true;
          }
          all_metas.insert(def.name.clone(), meta);
        },
        MutConst::Indc(ind) => {
          let (data, meta, ctor_metas) =
            compile_inductive(ind, &mut_ctx, &mut cache, stt)?;
          if !rep_pushed {
            ixon_mutuals.push(IxonMutConst::Indc(data));
            rep_pushed = true;
          }
          all_metas.insert(ind.ind.cnst.name.clone(), meta);
          for (ctor, cm) in ind.ctors.iter().zip(ctor_metas) {
            all_metas.insert(ctor.cnst.name.clone(), cm);
          }
        },
      }
    }
  }

  // Compile the mutual block.
  let block_refs: Vec<Address> = cache.refs.iter().cloned().collect();
  let block_univs: Vec<Arc<Univ>> = cache.univs.iter().cloned().collect();
  let name_str = aux_consts[0].name().pretty();
  let compiled = compile_mutual_block(
    ixon_mutuals,
    block_refs,
    block_univs,
    Some(&name_str),
  );
  let block_addr = compiled.addr.clone();
  stt.env.store_const(block_addr.clone(), compiled.constant);

  // Register projections for each constant, same pattern as compile_mutual.
  // Collect names for batched pending-queue push (one lock acquisition).
  let mut pending_names: Vec<Name> = Vec::new();

  let singleton = sorted_classes.len() == 1
    && !aux_consts.iter().any(|c| matches!(c, MutConst::Indc(_)));

  if singleton {
    // Single non-inductive class: register directly with block_addr.
    for cnst in &sorted_classes[0] {
      let canon_n = cnst.name();
      let n = resolve_name(&canon_n);
      // Meta was keyed by canonical name during compile; transfer to
      // source name at lookup but preserve the meta payload.
      let meta = all_metas.remove(&canon_n).unwrap_or_default();
      stt.env.register_name(n.clone(), Named::new(block_addr.clone(), meta));
      stt.aux_name_to_addr.insert(n.clone(), block_addr.clone());
      stt.aux_gen_extra_names.insert(n.clone());
      pending_names.push(n);
    }
  } else {
    // Multi-class or inductive: create projections per member.
    for (idx, class) in sorted_classes.iter().enumerate() {
      let idx = idx as u64;
      for cnst in class {
        let canon_n = cnst.name();
        let n = resolve_name(&canon_n);
        let meta = all_metas.get(&canon_n).cloned().unwrap_or_default();

        match cnst {
          MutConst::Indc(ind) => {
            // Inductive projection
            let indc_proj = Constant::new(ConstantInfo::IPrj(InductiveProj {
              idx,
              block: block_addr.clone(),
            }));
            let proj_addr = content_address(&indc_proj);
            stt.env.store_const(proj_addr.clone(), indc_proj);
            stt
              .env
              .register_name(n.clone(), Named::new(proj_addr.clone(), meta));
            stt.aux_name_to_addr.insert(n.clone(), proj_addr.clone());
            stt.aux_gen_extra_names.insert(n.clone());
            pending_names.push(n);

            // Constructor projections. Inductives don't typically get a
            // source-name remap for ctors (rename map is applied to the
            // inductive name only for nested aux cases, and those use
            // structural ctor naming via name_replace_prefix). Ctor names
            // pass through unchanged.
            for (cidx, ctor) in ind.ctors.iter().enumerate() {
              let ctor_meta =
                all_metas.get(&ctor.cnst.name).cloned().unwrap_or_default();
              let ctor_proj =
                Constant::new(ConstantInfo::CPrj(ConstructorProj {
                  idx,
                  cidx: cidx as u64,
                  block: block_addr.clone(),
                }));
              let ctor_addr = content_address(&ctor_proj);
              stt.env.store_const(ctor_addr.clone(), ctor_proj);
              stt.env.register_name(
                ctor.cnst.name.clone(),
                Named::new(ctor_addr.clone(), ctor_meta),
              );
              stt
                .aux_name_to_addr
                .insert(ctor.cnst.name.clone(), ctor_addr.clone());
              stt.aux_gen_extra_names.insert(ctor.cnst.name.clone());
              pending_names.push(ctor.cnst.name.clone());
            }
          },
          MutConst::Recr(_) => {
            let proj = Constant::new(ConstantInfo::RPrj(RecursorProj {
              idx,
              block: block_addr.clone(),
            }));
            let proj_addr = content_address(&proj);
            stt.env.store_const(proj_addr.clone(), proj);
            stt
              .env
              .register_name(n.clone(), Named::new(proj_addr.clone(), meta));
            stt.aux_name_to_addr.insert(n.clone(), proj_addr);
            stt.aux_gen_extra_names.insert(n.clone());
            pending_names.push(n);
          },
          MutConst::Defn(_) => {
            let proj = Constant::new(ConstantInfo::DPrj(DefinitionProj {
              idx,
              block: block_addr.clone(),
            }));
            let proj_addr = content_address(&proj);
            stt.env.store_const(proj_addr.clone(), proj);
            stt
              .env
              .register_name(n.clone(), Named::new(proj_addr.clone(), meta));
            stt.aux_name_to_addr.insert(n.clone(), proj_addr);
            stt.aux_gen_extra_names.insert(n.clone());
            pending_names.push(n);
          },
        }
      }
    }
  }

  // Register the synthetic Muts named entry for this block. `block_addr`
  // stores an `IxonCI::Muts(...)` constant, but kernel ingress only
  // discovers mutual blocks by finding a named entry tagged
  // `ConstantMetaInfo::Muts { all }` and calling `ingress_muts_block` on
  // it. Without this entry, ingress never routes the block's members into
  // the kernel env, and downstream checks fail with `UnknownConst`.
  //
  // The key is a synthetic `Ix.<block_addr_hex>.<first_member>` name
  // produced by `Address::muts_name`, so alpha-equivalent blocks with
  // different member names get distinct entries. `all` is a 2-D array of
  // name-hash addresses, one class per mutual component.
  let first_name_canonical =
    sorted_classes.first().and_then(|c| c.first()).map(|c| c.name()).expect(
      "compile_aux_block invariant: at least one class with one member",
    );
  let first_name = resolve_name(&first_name_canonical);
  // Build muts_all using *source* names (after rename). Kernel ingress
  // (`ingress_muts_block`) looks up `muts_all[i][0]` in `ixon_env.named`
  // to resolve each class's canonical-position primary name to its
  // Named entry; we registered source names above, so `muts_all` must
  // carry source-name hashes to match.
  let muts_all: Vec<Vec<Address>> = sorted_classes
    .iter()
    .map(|class| {
      class
        .iter()
        .map(|c| {
          let n = resolve_name(&c.name());
          Address::from_blake3_hash(*n.get_hash())
        })
        .collect()
    })
    .collect();
  let muts_name = block_addr.muts_name(&first_name);
  compile_name(&muts_name, stt);
  // `compile_aux_block_with_rename` handles derivative blocks (rec, below,
  // brecOn, ...) that share the same aux_layout as the primary inductive
  // block. We DO NOT attach aux_layout here — those derived blocks inherit
  // layout through their projection addresses into the primary's rec/aux
  // block, and decompile resolves layout via the primary inductive's Muts
  // meta (see `compile.rs:3254` for the primary-block registration and
  // `decompile_block_aux_gen` for the lookup).
  stt.env.register_name(
    muts_name,
    Named::new(
      block_addr.clone(),
      ConstantMeta::new(ConstantMetaInfo::Muts {
        all: muts_all,
        aux_layout: None,
      }),
    ),
  );

  // Batch-push to pending queue (single lock acquisition).
  if !pending_names.is_empty() {
    stt.aux_gen_pending.lock().unwrap().extend(pending_names);
  }

  // Ingress all registered aux constants into the kernel environment.
  for cnst in aux_consts {
    aux_gen::expr_utils::ensure_in_kenv(&cnst.name(), lean_env.as_ref(), stt);
  }

  Ok(())
}

/// Register Lean-source aux names as aliases of already-compiled canonical
/// aux_gen patches. This preserves one compiled constant per canonical class
/// while still letting scheduler deps and later original-form compilation
/// resolve every real Lean-exported aux name.
fn register_aux_aliases(
  aliases: &FxHashMap<Name, Name>,
  stt: &CompileState,
) -> Result<(), CompileError> {
  if aliases.is_empty() {
    return Ok(());
  }

  let mut entries: Vec<(Name, Name)> = aliases
    .iter()
    .map(|(source, target)| (source.clone(), target.clone()))
    .collect();
  entries.sort_by_key(|(source, target)| (source.pretty(), target.pretty()));

  let mut pending_names = Vec::new();
  for (source, target) in entries {
    if source == target {
      continue;
    }

    let target_addr = stt.resolve_addr(&target).ok_or_else(|| {
      CompileError::InvalidMutualBlock {
        reason: format!(
          "aux_gen alias target '{}' for '{}' has not been compiled",
          target.pretty(),
          source.pretty(),
        ),
      }
    })?;

    if let Some(existing_addr) = stt.resolve_addr(&source) {
      if existing_addr != target_addr {
        return Err(CompileError::InvalidMutualBlock {
          reason: format!(
            "aux_gen alias '{}' already resolves to {:.12}, expected {:.12} via '{}'",
            source.pretty(),
            existing_addr.hex(),
            target_addr.hex(),
            target.pretty(),
          ),
        });
      }
      continue;
    }

    let target_named = stt
      .env
      .lookup_name(&target)
      .unwrap_or_else(|| Named::with_addr(target_addr.clone()));
    let mut alias_named = target_named;
    alias_named.addr = target_addr.clone();

    compile_name(&source, stt);
    stt.env.register_name(source.clone(), alias_named);
    stt.aux_name_to_addr.insert(source.clone(), target_addr);
    stt.aux_gen_extra_names.insert(source.clone());
    pending_names.push(source);
  }

  if !pending_names.is_empty() {
    stt.aux_gen_pending.lock().unwrap().extend(pending_names);
  }

  Ok(())
}

/// Compute the content-addressed hash for a Constant.
fn content_address(constant: &Constant) -> Address {
  let mut bytes = Vec::new();
  constant.put(&mut bytes);
  Address::hash(&bytes)
}

// ===========================================================================
// generate_and_compile_aux_recursors
// ===========================================================================

/// Generate and compile auxiliary constants for an alpha-collapsed inductive
/// block.
///
/// Called from `compile_mutual` after projections are registered. Runs the
/// full aux_gen pipeline:
///
/// 1. Generate patches (recursors, `.below`, `.brecOn`)
/// 2. Compile recursors
/// 3. Compile `.below` inductives (Prop) or definitions (Type)
/// 4. Compile `.below.rec` (for Prop `.below` inductives)
/// 5. Compile `.brecOn` in batched order (`.go`, main, `.eq`)
///
/// Only runs for inductive blocks. Non-inductive mutual blocks return
/// immediately.
pub(crate) fn generate_and_compile_aux_recursors(
  cs: &[MutConst],
  class_names: &[Vec<Name>],
  lean_env: &Arc<LeanEnv>,
  stt: &CompileState,
) -> Result<Option<crate::ix::compile::surgery::AuxLayout>, CompileError> {
  // Phase 0: optionally verify every Lean-original constant in this block
  // against the separate original kernel env, populated only when
  // `CompileOptions::check_originals` is enabled.
  //
  // This is enabled for adversarial raw-constant tests. Normal compilation
  // from a trusted Lean environment leaves it off to avoid retaining a
  // second kernel-form copy of the full env.
  check_originals(cs, lean_env, stt)?;

  // Guard: aux_gen canonical generation only runs for blocks containing
  // inductives. Non-inductive blocks (plain defs, recursor-only SCCs,
  // etc.) have no canonical auxiliaries to generate.
  let is_inductive_block = cs.iter().any(|c| matches!(c, MutConst::Indc(_)));
  if !is_inductive_block {
    return Ok(None);
  }

  let aux_total_start = std::time::Instant::now();
  let block_label = class_names
    .first()
    .and_then(|c| c.first())
    .map(|n| n.pretty())
    .unwrap_or_default();

  // Extract Lean's source-walk `all` list from the first inductive in the
  // block. `generate_aux_patches` uses this for source-indexed aux naming
  // (`<all0>.rec_{source_j+1}`) and for the hash-sort permutation it
  // returns.
  let source_all: Vec<Name> = cs
    .iter()
    .find_map(|c| match c {
      MutConst::Indc(ind) => Some(ind.ind.all.clone()),
      _ => None,
    })
    .unwrap_or_default();
  if source_all.is_empty() {
    return Ok(None);
  }

  // Aux generation is defined relative to the Lean inductive declaration
  // (`InductiveVal.all`) after canonical collapse/splitting. The scheduler SCC
  // can contain extra inductive declarations through ordinary dependency
  // cycles; those must not become primary recursor motives for this source
  // declaration. Intersect with `.all`: over-merge splitting naturally leaves
  // only the members present in this SCC, while alpha-collapse keeps the
  // canonical class representatives.
  let source_all_lookup: FxHashMap<Name, ()> =
    source_all.iter().cloned().map(|n| (n, ())).collect();
  let aux_class_names: Vec<Vec<Name>> = class_names
    .iter()
    .filter_map(|class| {
      let names: Vec<Name> = class
        .iter()
        .filter(|n| source_all_lookup.contains_key(*n))
        .cloned()
        .collect();
      (!names.is_empty()).then_some(names)
    })
    .collect();
  if aux_class_names.is_empty() {
    return Ok(None);
  }

  // Phase 1: Generate patches. Errors here indicate a bug in aux_gen
  // (the input has already been validated by sort_consts and the compile
  // loop), so we propagate rather than swallow.
  let t0 = std::time::Instant::now();
  let aux_out = aux_gen::generate_aux_patches(
    &aux_class_names,
    &source_all,
    lean_env,
    stt,
    &stt.kctx,
  )?;
  let patches = &aux_out.patches;
  let gen_elapsed = t0.elapsed();
  if patches.is_empty() {
    return Ok(None);
  }

  // Record the nested-auxiliary permutation mapping Lean's source-walk
  // aux position to our canonical aux position.
  //
  // `aux_gen::generate_aux_patches` internally canonicalizes the expanded
  // block's aux section and returns `perm[source_j] = canonical_i` via
  // `AuxPatchesOutput.perm`. We record it here keyed by
  // `InductiveVal.all[0]` for:
  //   1. Call-site surgery plans (built below in compile.rs:compile_mutual)
  //      so they can permute source-order aux motives/minors to canonical.
  //   2. Compile_aux_block, to register Lean-source aux names at the
  //      permuted block projection index (so user code calling `X.rec_1`
  //      resolves to whatever aux Lean originally numbered `_1`, not
  //      whatever aux happens to sort to canonical position 0).
  //
  // `original_all` (= `source_all` above) is hoisted to the enclosing
  // scope so the aux-name rename map construction below can reuse it.
  let original_all: Vec<Name> = source_all;
  let mut aux_layout: Option<crate::ix::compile::surgery::AuxLayout> = None;
  if !original_all.is_empty()
    && let Some(perm) = aux_out.perm.clone()
    && !perm.is_empty()
  {
    // Also compute per-source-aux ctor counts: for each source aux position j,
    // look up the external inductive's constructor count. If this metadata is
    // unavailable, fail closed: silently dropping `perm` makes call-site
    // surgery fall back to identity, which is wrong precisely for the
    // alpha-collapse / reordered cases that need the permutation.
    let src_order = aux_gen::nested::source_aux_order(&original_all, lean_env)?;
    let mut source_ctor_counts: Vec<usize> =
      Vec::with_capacity(src_order.len());
    for (head, _) in &src_order {
      match lean_env.get(head) {
        Some(LeanConstantInfo::InductInfo(v)) => {
          source_ctor_counts.push(v.ctors.len());
        },
        _ => {
          return Err(CompileError::MissingConstant {
            name: head.pretty(),
            caller: "compile_aux_block(aux_layout.source_ctor_counts)".into(),
          });
        },
      }
    }
    if source_ctor_counts.len() != perm.len() {
      return Err(CompileError::InvalidMutualBlock {
        reason: format!(
          "aux layout mismatch: {} source aux ctor counts for {} permutation entries",
          source_ctor_counts.len(),
          perm.len()
        ),
      });
    }
    aux_layout =
      Some(crate::ix::compile::surgery::AuxLayout { perm, source_ctor_counts });
  }

  // NOTE: Historically, a canonical→source rename map was built here
  // to bridge aux_gen's canonical-indexed names (`rec_{canonical_i+1}`)
  // to Lean's source-walk names (`rec_{source_j+1}`). Since aux_gen
  // now emits patches with source-indexed names directly (via
  // `canon_repr` in `generate_aux_patches`), the rename is redundant
  // and double-applies. Pass an empty map to `compile_aux_block_with_rename`
  // — the `resolve_name` closure becomes identity.
  let aux_name_rename: FxHashMap<Name, Name> = FxHashMap::default();

  // Phase 2: Compile canonical recursors.
  //
  // The recursor block's storage order must align with the inductive
  // block's flat layout, so the kernel's
  // `populate_recursor_rules_from_block` can match `rec_block[i]` with
  // `flat[i]` positionally (no signature search). The desired order is:
  //
  //   * positions `[0..n_originals)`: rec for original i, in inductive
  //     block class order (`aux_class_names`, which mirrors
  //     `compile_mutual`'s `sorted_classes` filtered to inductives).
  //   * positions `[n_originals..total)`: rec for canonical aux ci.
  //     Aux recursor name is `<original_all[0]>.rec_{source_j+1}` where
  //     `source_j = source_of_canonical[ci]` (min source position
  //     mapping to that canonical aux).
  //
  // We build a name → canonical-position map, then pass it to
  // `compile_aux_block_with_rename` as a class-order key so the recursor
  // block lays out classes in canonical position order. Without this,
  // `sort_consts` on recursors would pick its own (independent)
  // permutation that diverges from the inductive block — see the
  // `populate_recursor_rules_from_block` comment in the kernel.
  let t1 = std::time::Instant::now();
  let rec_consts: Vec<MutConst> = patches
    .iter()
    .filter_map(|(_, p)| match p {
      PatchedConstant::Rec(r) => Some(MutConst::Recr(r.clone())),
      _ => None,
    })
    .collect();
  if !rec_consts.is_empty() {
    let mut name_to_pos: FxHashMap<Name, u64> = FxHashMap::default();
    let n_originals_in_block = aux_class_names.len();
    for (pos, class) in aux_class_names.iter().enumerate() {
      for member_name in class {
        let rec_name = Name::str(member_name.clone(), "rec".to_string());
        name_to_pos.insert(rec_name, pos as u64);
      }
    }
    if let Some(perm) = aux_out.perm.as_ref()
      && !perm.is_empty()
    {
      let n_canon = aux_out.n_canonical_aux;
      let mut source_of_canonical: Vec<usize> = vec![usize::MAX; n_canon];
      for (src_j, &canon_i) in perm.iter().enumerate() {
        if canon_i < n_canon && source_of_canonical[canon_i] == usize::MAX {
          source_of_canonical[canon_i] = src_j;
        }
      }
      for (canonical_i, &source_j) in source_of_canonical.iter().enumerate() {
        if source_j == usize::MAX {
          continue;
        }
        let aux_rec_name = Name::str(
          original_all[0].clone(),
          format!("rec_{}", source_j + 1),
        );
        name_to_pos
          .insert(aux_rec_name, (n_originals_in_block + canonical_i) as u64);
      }
    }
    let class_order_key = |c: &MutConst| -> u64 {
      name_to_pos.get(&c.name()).copied().unwrap_or(u64::MAX)
    };
    compile_aux_block_with_rename(
      &rec_consts,
      lean_env,
      stt,
      Some(&aux_name_rename),
      Some(&class_order_key),
    )?;
  }
  // Some later generated wrappers are named under alpha-collapsed aliases
  // and may reference the alias `.rec` name. Register every alias whose target
  // was compiled by the recursor phase now; remaining aliases (.below_N,
  // .brecOn_N, etc.) are registered after their phases below.
  let available_rec_aliases: FxHashMap<Name, Name> = aux_out
    .aliases
    .iter()
    .filter(|(_, target)| stt.resolve_addr(target).is_some())
    .map(|(source, target)| (source.clone(), target.clone()))
    .collect();
  register_aux_aliases(&available_rec_aliases, stt)?;
  let rec_elapsed = t1.elapsed();
  // Phase 2b: Compile .casesOn definitions.
  // casesOn wraps .rec and must be compiled after .rec but before .brecOn
  // (because .brecOn.eq references casesOn).
  let t2 = std::time::Instant::now();
  let cases_on_defs: Vec<MutConst> = patches
    .iter()
    .filter_map(|(_, p)| match p {
      PatchedConstant::CasesOn(d) => Some(MutConst::Defn(Def {
        name: d.name.clone(),
        level_params: d.level_params.clone(),
        typ: d.typ.clone(),
        kind: DefKind::Definition,
        value: d.value.clone(),
        hints: ReducibilityHints::Abbrev,
        safety: def_safety(d.is_unsafe),
        all: vec![],
      })),
      _ => None,
    })
    .collect();
  if !cases_on_defs.is_empty() {
    compile_aux_block(&cases_on_defs, lean_env, stt)?;
  }
  let cases_elapsed = t2.elapsed();

  // Phase 2c: Compile .recOn definitions (arg-reordered .rec wrapper).
  // recOn wraps .rec and must be compiled after .rec.
  let t3 = std::time::Instant::now();
  let rec_on_defs: Vec<MutConst> = patches
    .iter()
    .filter_map(|(_, p)| match p {
      PatchedConstant::RecOn(d) => Some(MutConst::Defn(Def {
        name: d.name.clone(),
        level_params: d.level_params.clone(),
        typ: d.typ.clone(),
        kind: DefKind::Definition,
        value: d.value.clone(),
        hints: ReducibilityHints::Abbrev,
        safety: def_safety(d.is_unsafe),
        all: vec![],
      })),
      _ => None,
    })
    .collect();
  if !rec_on_defs.is_empty() {
    compile_aux_block(&rec_on_defs, lean_env, stt)?;
  }
  let rec_on_elapsed = t3.elapsed();
  // Phase 3: Compile .below inductives (Prop-level).
  // Collect all .below names first for the mutual `all` field.
  let t4 = std::time::Instant::now();
  let all_below_names: Vec<Name> = patches
    .iter()
    .filter_map(|(_, p)| match p {
      PatchedConstant::BelowIndc(bi) => Some(bi.name.clone()),
      _ => None,
    })
    .collect();
  let below_indcs: Vec<MutConst> = patches
    .iter()
    .filter_map(|(_, p)| match p {
      PatchedConstant::BelowIndc(bi) => {
        Some(below_indc_to_mut_const(bi, &all_below_names))
      },
      _ => None,
    })
    .collect();
  if !below_indcs.is_empty() {
    compile_aux_block_with_rename(
      &below_indcs,
      lean_env,
      stt,
      Some(&aux_name_rename),
      None,
    )?;
    // Note: constructor names are already correctly set by rename_below_indc
    // during alias patching. register_below_ctor_aliases was removed because
    // it created spurious cross-aliases (e.g., Z.below.x for alpha-collapsed
    // blocks) that don't exist in the Lean environment.
  }

  // Phase 4: Compile .below definitions (Type-level).
  let below_defs: Vec<MutConst> = patches
    .iter()
    .filter_map(|(_, p)| match p {
      PatchedConstant::BelowDef(d) => Some(MutConst::Defn(Def {
        name: d.name.clone(),
        level_params: d.level_params.clone(),
        typ: d.typ.clone(),
        kind: DefKind::Definition,
        value: d.value.clone(),
        hints: ReducibilityHints::Abbrev,
        safety: def_safety(d.is_unsafe),
        all: vec![],
      })),
      _ => None,
    })
    .collect();
  if !below_defs.is_empty() {
    compile_aux_block_with_rename(
      &below_defs,
      lean_env,
      stt,
      Some(&aux_name_rename),
      None,
    )?;
  }
  let below_elapsed = t4.elapsed();

  // Phase 5: Compile .below.rec (for Prop-level .below inductives).
  let t5 = std::time::Instant::now();
  if !below_indcs.is_empty() {
    compile_below_recursors(&below_indcs, lean_env, stt)?;
  }
  let below_rec_elapsed = t5.elapsed();

  // Phase 6: Compile .brecOn in 3 batches (.go first, main second, .eq last).
  let t6 = std::time::Instant::now();
  for batch in 0..3u8 {
    let defs: Vec<MutConst> = patches
      .iter()
      .filter_map(|(_, p)| match p {
        PatchedConstant::BRecOn(d) if brecon_batch(&d.name) == batch => {
          Some(brecon_to_mut_const(d))
        },
        _ => None,
      })
      .collect();
    if !defs.is_empty() {
      compile_aux_block_with_rename(
        &defs,
        lean_env,
        stt,
        Some(&aux_name_rename),
        None,
      )?;
    }
  }
  let brecon_elapsed = t6.elapsed();

  register_aux_aliases(&aux_out.aliases, stt)?;

  // Note: `.noConfusion`, `.noConfusionType`, `.ctor.noConfusion`, `.ctorIdx`,
  // `.ctorElim*`, `.ctor.inj*`, `._sizeOf_*`, etc. are **not** regenerated.
  // Their bodies only invoke `.casesOn` (never `.rec`), and `.casesOn`'s
  // public binder arity is invariant under alpha collapse. Compiling the
  // original Lean values as-is produces correct Ixon — they resolve to our
  // regenerated `.casesOn` at address-resolution time. The validate-aux
  // roundtrip test confirms this empirically (0 mismatches across 25k+
  // constants, including these auxiliaries for alpha-collapsed multi-ctor
  // blocks). See the aux_gen.rs module docs for the full rationale.

  let total = aux_total_start.elapsed();
  if *crate::ix::compile::IX_TIMING && total.as_secs_f32() > 0.5 {
    eprintln!(
      "[aux_gen] {:?} total={:.2}s gen={:.2}s rec={:.2}s cases={:.2}s recOn={:.2}s below={:.2}s belowRec={:.2}s brecon={:.2}s patches={}",
      block_label,
      total.as_secs_f32(),
      gen_elapsed.as_secs_f32(),
      rec_elapsed.as_secs_f32(),
      cases_elapsed.as_secs_f32(),
      rec_on_elapsed.as_secs_f32(),
      below_elapsed.as_secs_f32(),
      below_rec_elapsed.as_secs_f32(),
      brecon_elapsed.as_secs_f32(),
      patches.len(),
    );
  }
  Ok(aux_layout)
}

// ===========================================================================
// check_originals
// ===========================================================================

/// Type-check every original Lean-stored constant in the inductive block
/// (the inductives, their constructors, and their recursors) **before** any
/// aux_gen work runs, against the pristine `orig_kenv`.
///
/// This check only runs when `CompileOptions::check_originals` is enabled.
/// Fast trusted-environment callers leave it disabled and keep `orig_kenv`
/// empty.
///
/// ## Why this runs at Phase 0
///
/// aux_gen's Phase 1 (`compute_is_large_and_k`) populates the canonical
/// `kctx.kenv` with ctor types pulled from an **expand/restore overlay**,
/// where fields that nest a foreign inductive (e.g. `Array X`) get
/// rewritten to reference a synthetic aux inductive (`X._nested.Array_1`).
/// That representation is correct for canonical recursor *generation*,
/// but it's *not* what Lean's stored originals refer to — the stored
/// forms are already `restore_nested`-processed: `Array X` everywhere,
/// no `_nested.*` refs.
///
/// Running this check at Phase 0, against `orig_kenv` when the caller opted
/// into building it via `lean_ingress`, sidesteps that entirely. `orig_kenv`
/// holds every Lean-original constant at its LEON content-hash address with
/// all type references self-consistent — no alpha-collapse, no aux rewriting,
/// no staleness. Subsequent aux_gen phases then freely populate the canonical
/// `kctx.kenv` without any risk of cross-contamination in either direction.
///
/// ## Approach
///
/// For each original inductive `I`, ctor `C`, and recursor `R` in `cs`:
/// - Look up its KId in `orig_kenv` (address =
///   `Address::from_blake3_hash(ConstantInfo::get_hash())`, name = the Lean
///   name).
/// - Run `tc.check_const(&kid)` against the orig_kenv's TypeChecker.
/// - Record failures under the Lean name in `stt.ungrounded`.
///
/// No ingress step, no shadow addresses, no dep walking. `orig_kenv`
/// already contains every Lean-original constant and every transitive
/// dep, all with consistent addressing.
fn check_originals(
  cs: &[MutConst],
  lean_env: &Arc<LeanEnv>,
  stt: &CompileState,
) -> Result<(), CompileError> {
  use crate::ix::address::Address;
  use crate::ix::kernel::id::KId;
  use crate::ix::kernel::mode::Meta;
  use crate::ix::kernel::tc::TypeChecker;

  if !stt.check_originals {
    return Ok(());
  }

  let orig_kenv = &stt.kctx.orig_kenv;

  // Build a KId for the given Lean name against the orig_kenv address
  // scheme. `lean_ingress` inserts every constant at its LEON content
  // hash (`ConstantInfo::get_hash()`), so `orig_kid` must compute the
  // same address. Returns `None` if the name isn't present in
  // `lean_env` — callers skip silently in that case (the constant was
  // filtered out of ingress, or the name dangles from a bad ref).
  let orig_kid = |name: &Name| -> Option<KId<Meta>> {
    let ci = lean_env.get(name)?;
    Some(KId::new(Address::from_blake3_hash(ci.get_hash()), name.clone()))
  };

  // Helper: run check_const on one KId and record any failure under the
  // given Lean name with the supplied error-prefix.
  let run_check = |lean_name: &Name, kid: &KId<Meta>, kind: &str| {
    if !orig_kenv.contains_key(kid) {
      // The original wasn't ingressed (e.g., it was filtered out of
      // the lean_env input, or the caller's block refers to a name
      // that Lean's kernel rejected so it never landed in
      // env.constants). Skip silently — compile_const will report
      // the missing-constant condition later.
      return;
    }
    let mut tc = TypeChecker::new(orig_kenv.clone());
    if let Err(e) = tc.check_const(kid) {
      stt.ungrounded.insert(
        lean_name.clone(),
        format!("original {kind} rejected: {}: {e}", lean_name.pretty()),
      );
    }
  };

  // Which recursor names might Lean have generated for an inductive
  // with mutual-group members `all`? `I.rec` is the primary; aux-nested
  // inductives also get `I.rec_1`, `I.rec_2`, ... (one per auxiliary
  // created by `elim_nested_inductive_fn`). Empirically 8 aux recursors
  // is more than enough for any Lean inductive we've seen; we probe
  // each in `lean_env` and only check those that exist.
  //
  // We probe through `lean_env` (not restricted to names in `cs`)
  // because a bad recursor can live in its own Recr-only SCC that
  // `compile_mutual` processes with `cs = [Recr(bad_rec)]`, handled by
  // the `MutConst::Recr` branch below — or as an orphan that never
  // reaches us via `cs`, handled here.
  fn recursor_names(ind_name: &Name) -> Vec<Name> {
    let mut names = Vec::new();
    names.push(Name::str(ind_name.clone(), "rec".to_string()));
    // Aux-recursor naming convention: `<main_ind>.rec_<N>` where
    // `<main_ind>` is the first inductive in the mutual block's `all`
    // list — see Lean's `mk_aux_rec_name_map` in
    // `refs/lean4/src/kernel/inductive.cpp`. Callers pass each `ind` in
    // `all` here; the first one's `<name>.rec_N` probes will hit, the
    // others' probes will simply miss `lean_env` and be skipped.
    let rec_base = Name::str(ind_name.clone(), "rec".to_string());
    for i in 1u64..=16 {
      names.push(Name::num(rec_base.clone(), Nat::from(i)));
    }
    names
  }

  for c in cs {
    match c {
      MutConst::Indc(ind) => {
        let ind_name = &ind.ind.cnst.name;
        if let Some(ind_kid) = orig_kid(ind_name) {
          run_check(ind_name, &ind_kid, "inductive");
        }
        for ctor in &ind.ctors {
          if let Some(ctor_kid) = orig_kid(&ctor.cnst.name) {
            run_check(&ctor.cnst.name, &ctor_kid, "ctor");
          }
        }
        // Probe for associated recursors in `lean_env` and check each
        // that exists. Covers the case where the recursor lives in a
        // separate SCC that `check_originals` wouldn't otherwise see.
        for rec_name in recursor_names(ind_name) {
          if let Some(rec_kid) = orig_kid(&rec_name) {
            run_check(&rec_name, &rec_kid, "rec");
          }
        }
      },
      MutConst::Recr(rec) => {
        let rec_name = &rec.cnst.name;
        if let Some(rec_kid) = orig_kid(rec_name) {
          run_check(rec_name, &rec_kid, "rec");
        }
      },
      // Non-inductive members aren't part of this check.
      MutConst::Defn(_) => {},
    }
  }

  Ok(())
}

// ===========================================================================
// Helpers
// ===========================================================================

/// Convert a `BelowIndc` (aux_gen output) to a `MutConst::Indc`.
/// `all_below_names` lists all `.below` inductives in the mutual block,
/// needed for the `all` field so `.below.rec` sees the full mutual structure.
fn below_indc_to_mut_const(
  bi: &BelowIndc,
  all_below_names: &[Name],
) -> MutConst {
  let ctor_vals: Vec<ConstructorVal> = bi
    .ctors
    .iter()
    .enumerate()
    .map(|(ci, c)| ConstructorVal {
      cnst: ConstantVal {
        name: c.name.clone(),
        level_params: bi.level_params.clone(),
        typ: c.typ.clone(),
      },
      induct: bi.name.clone(),
      cidx: Nat::from(ci as u64),
      num_params: Nat::from(c.n_params as u64),
      num_fields: Nat::from(c.n_fields as u64),
      // A `.below` constructor inherits the parent inductive's safety; Lean's
      // kernel requires ctor safety to match the enclosing inductive.
      is_unsafe: bi.is_unsafe,
    })
    .collect();

  MutConst::Indc(Ind {
    ind: crate::ix::env::InductiveVal {
      cnst: ConstantVal {
        name: bi.name.clone(),
        level_params: bi.level_params.clone(),
        typ: bi.typ.clone(),
      },
      num_params: Nat::from(bi.n_params as u64),
      // .below has original indices + 1 (the major premise)
      num_indices: Nat::from(bi.n_indices as u64),
      all: all_below_names.to_vec(),
      ctors: bi.ctors.iter().map(|c| c.name.clone()).collect(),
      is_rec: true,
      // Prop-level `.below` is an inductive; its safety mirrors the parent's
      // (via `IndPredBelow`). Hardcoding `false` here diverged from Lean's
      // content hash whenever the parent was `unsafe inductive`.
      is_unsafe: bi.is_unsafe,
      // Propagate reflexivity from the parent: a `.below` built from a
      // reflexive parent has higher-order recursive IH fields of its own
      // (`∀ ys, I.below ... (h ys)`). Hardcoding `false` here silently
      // diverges from Lean's auto-generated `.below` content hash for
      // inductives like `Acc` and `Lean.Order.iterates`.
      is_reflexive: bi.is_reflexive,
      num_nested: Nat::from(0u64),
    },
    ctors: ctor_vals,
  })
}

/// Convert a `BRecOnDef` to a `MutConst::Defn`.
///
/// Replicates Lean's per-kind decisions from `Lean/Meta/Constructions/BRecOn.lean`:
///
/// | Shape              | Kind        | Safety                | Hints    |
/// |--------------------|-------------|-----------------------|----------|
/// | `.brecOn` (Prop)   | `Theorem`   | inferred from unsafe  | default  |
/// | `.brecOn` (Type)   | `Definition`| inferred from unsafe  | `Abbrev` |
/// | `.brecOn.go`       | `Definition`| inferred from unsafe  | `Abbrev` |
/// | `.brecOn.eq` (safe)| `Theorem`   | `Safe`                | default  |
/// | `.brecOn.eq` (unsafe) | `Definition` | `Unsafe`           | `Opaque` |
///
/// The unsafe-`.eq` flip is driven by Lean's `mkThmOrUnsafeDef`
/// (`refs/lean4/src/Lean/Environment.lean:2797`), which replaces the theorem
/// declaration with an unsafe definition when `env.hasUnsafe` fires on the
/// type or value — always the case for unsafe inductives since the type
/// mentions the parent. `.brecOn` / `.brecOn.go` pick up their safety via
/// `mkDefinitionValInferringUnsafe` on the same predicate.
fn brecon_to_mut_const(d: &BRecOnDef) -> MutConst {
  let is_eq = d.name.last_str() == Some("eq");
  let is_go = d.name.last_str() == Some("go");

  // Determine kind.
  let kind = if is_eq {
    if d.is_unsafe { DefKind::Definition } else { DefKind::Theorem }
  } else if d.is_prop {
    // Prop-level `.brecOn` with non-unsafe inductive: Thm. Unsafe Prop
    // inductives are effectively impossible (Lean forbids `unsafe` in Prop),
    // but honor the flag anyway.
    if d.is_unsafe { DefKind::Definition } else { DefKind::Theorem }
  } else {
    // Type-level `.brecOn` / `.brecOn.go`.
    DefKind::Definition
  };

  // Hints: `.abbrev` for reducible aux definitions (matches Lean's
  // `mkDefinitionValInferringUnsafe … .abbrev`); `.opaque` for the unsafe-eq
  // case (per `mkThmOrUnsafeDef`). Theorems use the struct default (`Opaque`
  // internally, not serialized for Thm).
  let hints = if (is_eq && d.is_unsafe) || matches!(kind, DefKind::Theorem) {
    ReducibilityHints::Opaque
  } else {
    ReducibilityHints::Abbrev
  };

  let _ = is_go; // kind decision doesn't differentiate go from plain brecOn above
  MutConst::Defn(Def {
    name: d.name.clone(),
    level_params: d.level_params.clone(),
    typ: d.typ.clone(),
    kind,
    value: d.value.clone(),
    hints,
    safety: def_safety(d.is_unsafe),
    all: vec![],
  })
}

/// Map an `is_unsafe` flag to a `DefinitionSafety`. Isolated here so every
/// aux-constant emission site picks up the same rule; if we ever need to
/// distinguish `Partial` from `Unsafe` we can refine one place.
fn def_safety(is_unsafe: bool) -> DefinitionSafety {
  if is_unsafe { DefinitionSafety::Unsafe } else { DefinitionSafety::Safe }
}

/// Determine which batch a `.brecOn` definition belongs to.
///
/// Batch 0: `.brecOn.go` (must compile first, `.brecOn` references it)
/// Batch 1: `.brecOn` (the main definition)
/// Batch 2: `.brecOn.eq` (proof of unfolding equation, references `.brecOn`)
fn brecon_batch(name: &Name) -> u8 {
  match name.last_str() {
    Some("go") => 0,
    Some("eq") => 2,
    _ => 1,
  }
}

/// Compile `.below.rec` recursors for Prop-level `.below` inductives.
///
/// Augments the lean_env with the `.below` inductives and their constructors
/// (since they don't exist in the original environment), then generates
/// canonical recursors for ALL `.below` inductives as one mutual block.
fn compile_below_recursors(
  below_indcs: &[MutConst],
  lean_env: &Arc<LeanEnv>,
  stt: &CompileState,
) -> Result<(), CompileError> {
  // Build a small overlay with just the .below inductives + ctors.
  // These don't exist in the original lean_env, but generate_canonical_recursors
  // needs to look them up as class representatives. Using an overlay avoids
  // cloning the full ~197k-entry environment.
  let mut overlay: LeanEnv = LeanEnv::default();
  for c in below_indcs {
    if let MutConst::Indc(ind) = c {
      overlay.insert(
        ind.ind.cnst.name.clone(),
        LeanConstantInfo::InductInfo(ind.ind.clone()),
      );
      for ctor in &ind.ctors {
        overlay.insert(
          ctor.cnst.name.clone(),
          LeanConstantInfo::CtorInfo(ctor.clone()),
        );
      }
    }
  }

  // Generate recursors for all .below inductives as ONE mutual block.
  // Each .below goes in its own class, matching the structure of the
  // original Lean .below.rec (which is a mutual recursor over all .below types).
  let classes: Vec<Vec<Name>> = below_indcs
    .iter()
    .filter_map(|c| match c {
      MutConst::Indc(ind) => Some(vec![ind.ind.cnst.name.clone()]),
      _ => None,
    })
    .collect();

  if classes.is_empty() {
    return Ok(());
  }

  let mut below_recs: Vec<MutConst> = Vec::new();
  let (recs, _) = recursor::generate_canonical_recursors_with_overlay(
    &classes,
    lean_env,
    Some(&overlay),
    None,
    stt,
    &stt.kctx,
  )?;
  for (_, rec) in recs {
    below_recs.push(MutConst::Recr(rec));
  }

  if !below_recs.is_empty() {
    compile_aux_block(&below_recs, lean_env, stt)?;
  }
  Ok(())
}
